import { test, expect } from '@playwright/test';
import { signInAs, openChannel, sendMessage } from './fixtures';

test('mentioned member sees in-app banner in active channel', async ({ browser }) => {
  // Two browser contexts: alice (mentioner) and bob (recipient).
  const aliceCtx = await browser.newContext();
  const bobCtx = await browser.newContext();
  const alice = await aliceCtx.newPage();
  const bob = await bobCtx.newPage();

  await signInAs(alice, 'alice');
  await signInAs(bob, 'bob');

  // Both members are in channel c1 (seeded by test data).
  await openChannel(alice, 'c1');
  await openChannel(bob, 'c1');

  // Alice mentions bob.
  await sendMessage(alice, 'hey @m_bob can you look at this');

  // Bob should see the in-app banner — REQ-001's in-app banner surface.
  const banner = bob.locator('[data-test=in-app-banner]');
  await expect(banner).toBeVisible();
  await expect(banner).toHaveAttribute('data-test-banner-kind', 'mention');
  // The banner should reference the originating member.
  await expect(banner).toHaveAttribute('data-test-mention-from', 'm_alice');

  await aliceCtx.close();
  await bobCtx.close();
});
